import { describe, expect, it, beforeEach } from "bun:test"

import {
  anthropicToCopilotModelId,
  copilotToAnthropicModelId,
} from "./model-mapping"
import { state } from "./state"

// Helper to set up model catalog
function setCatalog(ids: Array<string>) {
  state.models = {
    object: "list",
    data: ids.map((id) => ({
      id,
      object: "model",
      created: 0,
      owned_by: "anthropic",
    })),
  } as unknown as typeof state.models
}

describe("anthropicToCopilotModelId", () => {
  beforeEach(() => {
    setCatalog(["claude-opus-4.6", "claude-opus-4.6-1m"])
  })

  it("maps dash format to dot format", () => {
    expect(anthropicToCopilotModelId("claude-opus-4-6", false)).toBe(
      "claude-opus-4.6",
    )
    expect(anthropicToCopilotModelId("claude-sonnet-4-6", false)).toBe(
      "claude-sonnet-4.6",
    )
    expect(anthropicToCopilotModelId("claude-opus-4-5", false)).toBe(
      "claude-opus-4.5",
    )
    expect(anthropicToCopilotModelId("claude-opus-4-7", false)).toBe(
      "claude-opus-4.7",
    )
  })

  it("handles [1m] suffix when model exists in catalog", () => {
    expect(anthropicToCopilotModelId("claude-opus-4-6[1m]", false)).toBe(
      "claude-opus-4.6-1m",
    )
  })

  it("strips [1m] suffix when model not in catalog", () => {
    expect(anthropicToCopilotModelId("claude-sonnet-4-6[1m]", false)).toBe(
      "claude-sonnet-4.6",
    )
  })

  it("passes through unknown models unchanged", () => {
    expect(anthropicToCopilotModelId("gpt-4o", false)).toBe("gpt-4o")
  })

  it("handles haiku models", () => {
    expect(anthropicToCopilotModelId("claude-haiku-4-5", false)).toBe(
      "claude-haiku-4.5",
    )
  })

  // ── -internal suffix resolution (backward compat) ──

  it("resolves to -1m when variant exists in catalog", () => {
    setCatalog(["claude-opus-4.7", "claude-opus-4.7-1m"])
    expect(anthropicToCopilotModelId("claude-opus-4.7", true)).toBe(
      "claude-opus-4.7-1m",
    )
    expect(anthropicToCopilotModelId("claude-opus-4.7[1m]", false)).toBe(
      "claude-opus-4.7-1m",
    )
  })

  it("falls back to base model when no -1m variant exists (1M is default)", () => {
    setCatalog(["claude-opus-4.7"])
    expect(anthropicToCopilotModelId("claude-opus-4.7", true)).toBe(
      "claude-opus-4.7",
    )
    expect(anthropicToCopilotModelId("claude-opus-4.7[1m]", false)).toBe(
      "claude-opus-4.7",
    )
  })

  it("prefers -1m over -1m-internal when both exist", () => {
    setCatalog([
      "claude-opus-4.8",
      "claude-opus-4.8-1m",
      "claude-opus-4.8-1m-internal",
    ])
    expect(anthropicToCopilotModelId("claude-opus-4.8", true)).toBe(
      "claude-opus-4.8-1m",
    )
  })

  // ── Effort suffixes are no longer handled in model mapping ──
  // Effort is sent via output_config.effort in the request body

  it("passes through model names with effort suffix unchanged (not a known mapping)", () => {
    setCatalog(["claude-opus-4.7"])
    // With effort suffix removed from model mapping, unrecognized suffixed names
    // pass through as-is. In practice, no client sends effort-suffixed names anymore.
    expect(anthropicToCopilotModelId("claude-opus-4-7-high", false)).toBe(
      "claude-opus-4-7-high",
    )
  })
})

describe("copilotToAnthropicModelId", () => {
  it("maps dot format to dash format", () => {
    expect(copilotToAnthropicModelId("claude-opus-4.6")).toBe("claude-opus-4-6")
    expect(copilotToAnthropicModelId("claude-opus-4.7")).toBe("claude-opus-4-7")
  })

  it("handles -1m suffix → [1m]", () => {
    expect(copilotToAnthropicModelId("claude-opus-4.6-1m")).toBe(
      "claude-opus-4-6[1m]",
    )
  })

  it("passes through unknown models unchanged", () => {
    expect(copilotToAnthropicModelId("gpt-4o")).toBe("gpt-4o")
  })

  // ── -internal suffix stripping ──

  it("strips -internal and maps -1m to [1m]", () => {
    expect(copilotToAnthropicModelId("claude-opus-4.7-1m-internal")).toBe(
      "claude-opus-4-7[1m]",
    )
  })

  it("strips -internal from non-1m models", () => {
    expect(copilotToAnthropicModelId("claude-opus-4.7-internal")).toBe(
      "claude-opus-4-7",
    )
  })

  // ── Effort suffix handling removed ──
  // These model IDs no longer exist. The upstream always returns base model
  // in response.model anyway (verified in upstream-model-id-report.md).
  // If they somehow appear, they pass through without special handling.

  it("passes through -high suffix unchanged (variant models no longer exist)", () => {
    expect(copilotToAnthropicModelId("claude-opus-4.7-high")).toBe(
      "claude-opus-4.7-high",
    )
  })

  it("passes through -xhigh suffix unchanged (variant models no longer exist)", () => {
    expect(copilotToAnthropicModelId("claude-opus-4.7-xhigh")).toBe(
      "claude-opus-4.7-xhigh",
    )
  })

  // ── Combined suffix scenarios ──

  it("handles -1m + -internal correctly (strip order matters)", () => {
    // This was the bug: endsWith("-1m") failed because it ended with "-1m-internal"
    // Must strip -internal FIRST, then check -1m
    const result = copilotToAnthropicModelId("claude-opus-4.7-1m-internal")
    expect(result).toBe("claude-opus-4-7[1m]")
    // Verify it doesn't produce "claude-opus-4-7-1m" (is1M=false bug)
    expect(result).not.toBe("claude-opus-4-7-1m")
    expect(result).not.toContain("-1m-")
  })

  // ── Full effort routing table ──
  // These test the reverse mapping that clients see in response.model

  it("response model table: base model", () => {
    expect(copilotToAnthropicModelId("claude-opus-4.7")).toBe("claude-opus-4-7")
  })

  it("response model table: effort variants pass through (upstream strips them anyway)", () => {
    // The upstream API returns base model in response.model regardless.
    // These IDs should never appear in practice, but if they do, they pass through.
    expect(copilotToAnthropicModelId("claude-opus-4.7-high")).toBe(
      "claude-opus-4.7-high",
    )
    expect(copilotToAnthropicModelId("claude-opus-4.7-xhigh")).toBe(
      "claude-opus-4.7-xhigh",
    )
  })

  it("response model table: 1m-internal variant", () => {
    expect(copilotToAnthropicModelId("claude-opus-4.7-1m-internal")).toBe(
      "claude-opus-4-7[1m]",
    )
  })

  it("response model table: 4.6 base", () => {
    expect(copilotToAnthropicModelId("claude-opus-4.6")).toBe("claude-opus-4-6")
  })

  it("response model table: 4.6-1m", () => {
    expect(copilotToAnthropicModelId("claude-opus-4.6-1m")).toBe(
      "claude-opus-4-6[1m]",
    )
  })

  // ── Non-Claude models should pass through ──

  it("GPT models pass through unchanged", () => {
    expect(copilotToAnthropicModelId("gpt-5.5")).toBe("gpt-5.5")
    expect(copilotToAnthropicModelId("gpt-5.5-2026-04-23")).toBe(
      "gpt-5.5-2026-04-23",
    )
  })

  it("Gemini models pass through unchanged", () => {
    expect(copilotToAnthropicModelId("gemini-2.5-pro")).toBe("gemini-2.5-pro")
  })
})

import { state } from "./state"

// Forward map: Anthropic dash format → Copilot dot format
const MODEL_ID_MAP: Record<string, string> = {
  "claude-opus-4-7": "claude-opus-4.7",
  "claude-opus-4-6": "claude-opus-4.6",
  "claude-opus-4-5": "claude-opus-4.5",
  "claude-sonnet-4-6": "claude-sonnet-4.6",
  "claude-sonnet-4-5": "claude-sonnet-4.5",
  "claude-sonnet-4": "claude-sonnet-4",
  "claude-opus-4": "claude-opus-4",
  "claude-haiku-4-5": "claude-haiku-4.5",
}

// Reverse map: Copilot dot format → Anthropic dash format
const REVERSE_MODEL_ID_MAP: Record<string, string> = Object.fromEntries(
  Object.entries(MODEL_ID_MAP).map(([k, v]) => [v, k]),
)

/**
 * Convert an Anthropic-style model ID to a Copilot-style model ID.
 * Strips date suffixes, converts dashes to dots, and appends -1m if needed.
 * Only appends -1m if the model actually has a 1M variant in the cached models.
 */
export function anthropicToCopilotModelId(
  model: string,
  is1M: boolean,
): string {
  let base = model

  // Strip [1m] suffix if present (Claude Code sends this)
  const has1MSuffix = base.endsWith("[1m]")
  if (has1MSuffix) {
    base = base.slice(0, -4)
  }

  // Strip date suffixes (e.g. claude-sonnet-4-20250514 → claude-sonnet-4)
  if (/^claude-sonnet-4-\d{8}/.test(base)) {
    base = "claude-sonnet-4"
  } else if (/^claude-opus-4-\d{8}/.test(base)) {
    base = "claude-opus-4"
  }

  const mapped = MODEL_ID_MAP[base] ?? base

  const use1M = is1M || has1MSuffix

  // Only append -1m if the 1M variant actually exists in the model catalog
  if (use1M) {
    const candidate = `${mapped}-1m`
    const exists = state.models?.data.some((m) => m.id === candidate)
    if (exists) return candidate
  }

  return mapped
}

/**
 * Convert a Copilot-style model ID back to Anthropic-style.
 * Converts dots to dashes and maps -1m back to [1m].
 * Strips -internal suffix (transient preview artifact).
 * Effort is handled via output_config in the request body, not in the model ID.
 */
export function copilotToAnthropicModelId(copilotModel: string): string {
  let base = copilotModel

  // Strip -internal (transient preview suffix)
  if (base.endsWith("-internal")) base = base.slice(0, -9)

  // Strip -1m
  const is1M = base.endsWith("-1m")
  if (is1M) base = base.slice(0, -3)

  const mapped = REVERSE_MODEL_ID_MAP[base] ?? base
  return is1M ? `${mapped}[1m]` : mapped
}

import type { Context } from "hono"

import consola from "consola"
import { streamSSE } from "hono/streaming"

import { awaitApproval } from "~/lib/approval"
import { resolveEndpoint } from "~/lib/endpoint-routing"
import { anthropicToCopilotModelId } from "~/lib/model-mapping"
import { checkRateLimit } from "~/lib/rate-limit"
import { state } from "~/lib/state"
import {
  createChatCompletions,
  type ChatCompletionChunk,
  type ChatCompletionResponse,
} from "~/services/copilot/create-chat-completions"
import {
  createResponses,
  createResponsesStreamState,
  translateResponsesStreamEvent,
} from "~/services/copilot/create-responses"
import {
  forwardNativeMessagesNonStreaming,
  forwardNativeMessagesStreaming,
} from "~/services/copilot/forward-native-messages"

import {
  type AnthropicMessagesPayload,
  type AnthropicStreamState,
} from "./anthropic-types"
import {
  translateToAnthropic,
  translateToOpenAI,
} from "./non-stream-translation"
import { translateChunkToAnthropicEvents } from "./stream-translation"

const CONTEXT_1M_BETA = "context-1m-2025-08-07"

/**
 * Check if the request wants 1M context via the anthropic-beta header.
 * The Claude Agent SDK sets `anthropic-beta: context-1m-2025-08-07`
 * instead of appending [1m] to the model name.
 */
function detectWants1M(c: Context): boolean {
  const betaHeader = c.req.header("anthropic-beta") ?? ""
  return betaHeader.split(",").some((s) => s.trim() === CONTEXT_1M_BETA)
}

export async function handleCompletion(c: Context) {
  await checkRateLimit(state)

  const anthropicPayload = await c.req.json<AnthropicMessagesPayload>()
  consola.debug("Anthropic request payload:", JSON.stringify(anthropicPayload))

  if (state.manualApprove) {
    await awaitApproval()
  }

  // Check per-request 1M context: anthropic-beta header or global flag
  const wants1M = detectWants1M(c) || state.is1MContext

  const copilotModelId = anthropicToCopilotModelId(
    anthropicPayload.model,
    wants1M,
  )
  const endpoint = resolveEndpoint(copilotModelId, state.models)

  // Native Anthropic passthrough for Claude models
  if (endpoint === "/v1/messages") {
    consola.debug(`Using native /v1/messages passthrough for ${copilotModelId}`)
    return handleNativePassthrough(c, anthropicPayload, wants1M)
  }

  // Translate Anthropic → OpenAI format for non-Claude models
  const openAIPayload = translateToOpenAI(anthropicPayload)
  consola.debug(
    "Translated OpenAI request payload:",
    JSON.stringify(openAIPayload),
  )

  // /responses for GPT-5.x models (responses-only or preferred)
  if (endpoint === "/responses") {
    consola.debug(`Using /responses endpoint for ${copilotModelId}`)
    return handleResponsesViaAnthropic(
      c,
      openAIPayload,
      anthropicPayload.output_config?.effort,
    )
  }

  // /chat/completions for legacy models
  const response = await createChatCompletions(openAIPayload)

  if (isNonStreaming(response)) {
    consola.debug(
      "Non-streaming response from Copilot:",
      JSON.stringify(response).slice(-400),
    )
    const anthropicResponse = translateToAnthropic(response)
    consola.debug(
      "Translated Anthropic response:",
      JSON.stringify(anthropicResponse),
    )
    return c.json(anthropicResponse)
  }

  consola.debug("Streaming response from Copilot")
  return streamSSE(c, async (stream) => {
    const streamState: AnthropicStreamState = {
      messageStartSent: false,
      contentBlockIndex: 0,
      contentBlockOpen: false,
      toolCalls: {},
    }

    for await (const rawEvent of response) {
      consola.debug("Copilot raw stream event:", JSON.stringify(rawEvent))
      if (rawEvent.data === "[DONE]") {
        break
      }

      if (!rawEvent.data) {
        continue
      }

      const chunk = JSON.parse(rawEvent.data) as ChatCompletionChunk
      const events = translateChunkToAnthropicEvents(chunk, streamState)

      for (const event of events) {
        consola.debug("Translated Anthropic event:", JSON.stringify(event))
        await stream.writeSSE({
          event: event.type,
          data: JSON.stringify(event),
        })
      }
    }
  })
}

async function handleNativePassthrough(
  c: Context,
  payload: AnthropicMessagesPayload,
  is1M: boolean,
) {
  if (!payload.stream) {
    const response = await forwardNativeMessagesNonStreaming(payload, is1M)
    return c.json(response)
  }

  return streamSSE(c, async (stream) => {
    for await (const event of forwardNativeMessagesStreaming(payload, is1M)) {
      await stream.writeSSE({
        event: event.type,
        data: JSON.stringify(event.data),
      })
    }
  })
}

const isNonStreaming = (
  response: Awaited<ReturnType<typeof createChatCompletions>>,
): response is ChatCompletionResponse => Object.hasOwn(response, "choices")

/**
 * Handle a request that needs the /responses endpoint but arrived via /v1/messages.
 * Flow: Anthropic payload → already translated to OpenAI → /responses → OpenAI response → Anthropic format.
 */
async function handleResponsesViaAnthropic(
  c: Context,
  openAIPayload: Parameters<typeof createResponses>[0],
  effort?: string,
) {
  const response = await createResponses(openAIPayload, effort)

  if (isNonStreaming(response)) {
    const anthropicResponse = translateToAnthropic(response)
    return c.json(anthropicResponse)
  }

  return streamSSE(c, async (stream) => {
    const responsesState = createResponsesStreamState()
    const anthropicState: AnthropicStreamState = {
      messageStartSent: false,
      contentBlockIndex: 0,
      contentBlockOpen: false,
      toolCalls: {},
    }

    for await (const rawEvent of response) {
      if (!rawEvent.data || rawEvent.data === "[DONE]") continue

      const parsed = JSON.parse(rawEvent.data) as Record<string, unknown>
      const eventType =
        rawEvent.event ?? (parsed.type as string | undefined) ?? ""

      const chunks = translateResponsesStreamEvent(
        { event: eventType, data: parsed },
        responsesState,
      )

      for (const chunk of chunks) {
        const events = translateChunkToAnthropicEvents(chunk, anthropicState)
        for (const event of events) {
          await stream.writeSSE({
            event: event.type,
            data: JSON.stringify(event),
          })
        }
      }
    }
  })
}

import consola from "consola"
import { events } from "fetch-event-stream"
import { randomUUID } from "node:crypto"

import { copilotBaseUrl, copilotHeaders } from "~/lib/api-config"
import { HTTPError } from "~/lib/error"
import { state } from "~/lib/state"

import type {
  ChatCompletionChunk,
  ChatCompletionResponse,
  ChatCompletionsPayload,
  ToolCall,
} from "./create-chat-completions"

// ── Request translation: OpenAI Chat Completions → Responses API ──

interface ResponsesPayload {
  model: string
  input: Array<ResponsesInput>
  max_output_tokens?: number
  tools?: Array<ResponsesTool>
  tool_choice?: string | { type: string; name?: string }
  stream?: boolean
  reasoning?: { effort: string }
}

type ResponsesInput =
  | {
      type: "message"
      role: "developer" | "user" | "assistant"
      content: string | Array<ResponsesContentPart>
    }
  | { type: "function_call"; name: string; arguments: string; call_id: string }
  | { type: "function_call_output"; call_id: string; output: string }

interface ResponsesContentPart {
  type: "input_text" | "input_image"
  text?: string
  image_url?: string
  detail?: string
}

interface ResponsesTool {
  type: "function"
  name: string
  description?: string
  parameters: Record<string, unknown>
}

function translateMessageContent(
  content:
    | string
    | Array<{
        type: string
        text?: string
        image_url?: { url: string; detail?: string }
      }>
    | undefined,
): string | Array<ResponsesContentPart> {
  if (typeof content === "string") return content
  if (!content) return ""
  return content.map((p) => {
    if (p.type === "text")
      return { type: "input_text" as const, text: p.text ?? "" }
    return {
      type: "input_image" as const,
      image_url: p.image_url?.url,
      detail: p.image_url?.detail,
    }
  })
}

function translateMessages(
  messages: ChatCompletionsPayload["messages"],
): Array<ResponsesInput> {
  const input: Array<ResponsesInput> = []

  for (const msg of messages) {
    switch (msg.role) {
      case "system":
      case "developer": {
        input.push({
          type: "message",
          role: "developer",
          content: translateMessageContent(msg.content ?? ""),
        })

        break
      }
      case "user": {
        input.push({
          type: "message",
          role: "user",
          content: translateMessageContent(msg.content ?? ""),
        })

        break
      }
      case "assistant": {
        // TODO: When Copilot starts populating reasoning summaries,
        // we should detect thinking blocks in msg.content and map them
        // to { type: "reasoning", summary: [{type: "summary_text", text}] }
        // instead of sending them as plain assistant text. Currently
        // thinking blocks are concatenated into content by translateToOpenAI,
        // which works functionally but loses semantic meaning for /responses.
        if (msg.content) {
          input.push({
            type: "message",
            role: "assistant",
            content: translateMessageContent(msg.content),
          })
        }
        if (msg.tool_calls) {
          for (const tc of msg.tool_calls) {
            input.push({
              type: "function_call",
              name: tc.function.name,
              arguments: tc.function.arguments,
              call_id: tc.id,
            })
          }
        }

        break
      }
      case "tool": {
        input.push({
          type: "function_call_output",
          call_id: msg.tool_call_id ?? "",
          output:
            typeof msg.content === "string" ?
              msg.content
            : JSON.stringify(msg.content),
        })

        break
      }
      // No default
    }
  }

  return input
}

function translateTools(
  payload: ChatCompletionsPayload,
): Partial<ResponsesPayload> {
  const result: Partial<ResponsesPayload> = {}

  if (payload.tools) {
    result.tools = payload.tools.map((t) => ({
      type: "function" as const,
      name: t.function.name,
      description: t.function.description,
      parameters: t.function.parameters,
    }))
  }

  if (payload.tool_choice) {
    result.tool_choice =
      typeof payload.tool_choice === "string" ?
        payload.tool_choice
      : { type: "function", name: payload.tool_choice.function.name }
  }

  return result
}

export function translateRequestToResponses(
  payload: ChatCompletionsPayload,
  effort?: string,
): ResponsesPayload {
  const result: ResponsesPayload = {
    model: payload.model,
    input: translateMessages(payload.messages),
    stream: payload.stream ?? undefined,
    ...translateTools(payload),
  }

  if (payload.max_tokens !== null && payload.max_tokens !== undefined)
    result.max_output_tokens = payload.max_tokens
  // Note: temperature and top_p are intentionally omitted — the /responses
  // API rejects them for GPT-5.x models ("Unsupported parameter").

  if (effort) result.reasoning = { effort }

  return result
}

// ── Response translation: Responses API → OpenAI Chat Completions ──

interface ResponsesResponse {
  id: string
  object: string
  created_at?: number
  model: string
  output: Array<ResponsesOutputItem>
  usage?: {
    input_tokens: number
    output_tokens: number
    total_tokens: number
  }
  status?: string
}

type ResponsesOutputItem =
  | {
      type: "message"
      role: "assistant"
      content: Array<ResponsesMessageContent>
    }
  | { type: "function_call"; name: string; arguments: string; call_id: string }
  | {
      type: "reasoning"
      id: string
      summary?: Array<{ type: "summary_text"; text: string }>
      encrypted_content?: string | null
    }

interface ResponsesMessageContent {
  type: "output_text"
  text: string
}

export function translateResponsesNonStreaming(
  resp: ResponsesResponse,
): ChatCompletionResponse {
  let textContent = ""
  let reasoningText = ""
  const toolCalls: Array<ToolCall> = []

  for (const item of resp.output) {
    switch (item.type) {
      case "message": {
        textContent += item.content.map((c) => c.text).join("")

        break
      }
      case "function_call": {
        toolCalls.push({
          id: item.call_id,
          type: "function",
          function: { name: item.name, arguments: item.arguments },
        })

        break
      }
      case "reasoning": {
        // Extract reasoning summary text if available
        if (item.summary && item.summary.length > 0) {
          reasoningText += item.summary.map((s) => s.text).join("\n")
        }

        break
      }
      // No default
    }
    // Skip other unknown item types
  }

  const finishReason = toolCalls.length > 0 ? "tool_calls" : "stop"

  return {
    id: resp.id,
    object: "chat.completion",
    created: resp.created_at ?? Math.floor(Date.now() / 1000),
    model: resp.model,
    choices: [
      {
        index: 0,
        message: {
          role: "assistant",
          content: textContent || null,
          ...(reasoningText ? { reasoning_text: reasoningText } : {}),
          ...(toolCalls.length > 0 ? { tool_calls: toolCalls } : {}),
        },
        logprobs: null,
        finish_reason: finishReason,
      },
    ],
    usage:
      resp.usage ?
        {
          prompt_tokens: resp.usage.input_tokens,
          completion_tokens: resp.usage.output_tokens,
          total_tokens: resp.usage.total_tokens,
        }
      : undefined,
  }
}

// ── Streaming translation: Responses API SSE → Chat Completions chunks ──

export interface ResponsesStreamState {
  responseId: string
  model: string
  toolCallIndex: number
  toolCallsByCallId: Partial<Record<string, ResponsesStreamToolCall>>
  toolCallsByOutputIndex: Partial<Record<number, ResponsesStreamToolCall>>
}

export function createResponsesStreamState(): ResponsesStreamState {
  return {
    responseId: "",
    model: "",
    toolCallIndex: 0,
    toolCallsByCallId: {},
    toolCallsByOutputIndex: {},
  }
}

interface ResponsesStreamToolCall {
  arguments: string
  callId: string
  index: number
  name: string
}

interface ResponsesStreamUsage {
  input_tokens: number
  output_tokens: number
  total_tokens: number
  input_tokens_details?: {
    cached_tokens: number
  }
}

interface ResponsesStreamResponse {
  id?: string
  model?: string
  usage?: ResponsesStreamUsage
}

interface ResponsesStreamItem {
  arguments?: string
  call_id?: string
  id?: string
  name?: string
  type?: string
}

interface ResponsesStreamEventData {
  arguments?: string
  call_id?: string
  delta?: string
  id?: string
  item?: ResponsesStreamItem
  model?: string
  name?: string
  output_index?: number
  response?: ResponsesStreamResponse
}

function makeChunk(
  streamState: ResponsesStreamState,
  {
    delta,
    finishReason,
    usage,
  }: {
    delta: Record<string, unknown>
    finishReason: string | null
    usage?: ChatCompletionChunk["usage"]
  },
): ChatCompletionChunk {
  return {
    id: streamState.responseId || `chatcmpl-${randomUUID()}`,
    object: "chat.completion.chunk",
    created: Math.floor(Date.now() / 1000),
    model: streamState.model,
    usage,
    choices: [
      {
        index: 0,
        delta: delta as ChatCompletionChunk["choices"][0]["delta"],
        finish_reason:
          finishReason as ChatCompletionChunk["choices"][0]["finish_reason"],
        logprobs: null,
      },
    ],
  }
}

function syncResponseMetadata(
  streamState: ResponsesStreamState,
  data: ResponsesStreamEventData,
) {
  streamState.responseId =
    data.response?.id ?? data.id ?? streamState.responseId
  streamState.model = data.response?.model ?? data.model ?? streamState.model
}

function translateResponsesUsage(
  usage: ResponsesStreamUsage | undefined,
): ChatCompletionChunk["usage"] | undefined {
  if (!usage) {
    return undefined
  }

  return {
    prompt_tokens: usage.input_tokens,
    completion_tokens: usage.output_tokens,
    total_tokens: usage.total_tokens,
    ...(usage.input_tokens_details && {
      prompt_tokens_details: {
        cached_tokens: usage.input_tokens_details.cached_tokens,
      },
    }),
  }
}

function getToolCallDelta(
  toolCall: ResponsesStreamToolCall,
  argumentsChunk: string,
): ChatCompletionChunk["choices"][0]["delta"] {
  return {
    tool_calls: [
      {
        index: toolCall.index,
        function: { arguments: argumentsChunk },
      },
    ],
  }
}

function getNewToolCallDelta(
  toolCall: ResponsesStreamToolCall,
  argumentsChunk: string,
): ChatCompletionChunk["choices"][0]["delta"] {
  return {
    tool_calls: [
      {
        index: toolCall.index,
        id: toolCall.callId,
        type: "function",
        function: {
          name: toolCall.name,
          arguments: argumentsChunk,
        },
      },
    ],
  }
}

function getExistingToolCall(
  streamState: ResponsesStreamState,
  data: Pick<ResponsesStreamEventData, "call_id" | "output_index">,
): ResponsesStreamToolCall | undefined {
  if (data.output_index !== undefined) {
    const outputIndexToolCall =
      streamState.toolCallsByOutputIndex[data.output_index]
    if (outputIndexToolCall) {
      return outputIndexToolCall
    }
  }

  return data.call_id ? streamState.toolCallsByCallId[data.call_id] : undefined
}

function getOrCreateToolCall(
  streamState: ResponsesStreamState,
  {
    callId,
    initialArguments = "",
    name,
    outputIndex,
  }: {
    callId?: string
    initialArguments?: string
    name?: string
    outputIndex?: number
  },
): { isNew: boolean; toolCall: ResponsesStreamToolCall } | undefined {
  if (!callId || !name) {
    return undefined
  }

  const existingToolCall =
    streamState.toolCallsByCallId[callId]
    ?? (outputIndex !== undefined ?
      streamState.toolCallsByOutputIndex[outputIndex]
    : undefined)

  if (existingToolCall) {
    streamState.toolCallsByCallId[callId] = existingToolCall
    if (outputIndex !== undefined) {
      streamState.toolCallsByOutputIndex[outputIndex] = existingToolCall
    }

    return { isNew: false, toolCall: existingToolCall }
  }

  const toolCall: ResponsesStreamToolCall = {
    arguments: initialArguments,
    callId,
    index: streamState.toolCallIndex,
    name,
  }

  streamState.toolCallsByCallId[callId] = toolCall
  if (outputIndex !== undefined) {
    streamState.toolCallsByOutputIndex[outputIndex] = toolCall
  }
  streamState.toolCallIndex++

  return { isNew: true, toolCall }
}

function* syncToolArguments(
  streamState: ResponsesStreamState,
  toolCall: ResponsesStreamToolCall,
  nextArguments: string | undefined,
): Generator<ChatCompletionChunk> {
  if (!nextArguments || nextArguments === toolCall.arguments) {
    return
  }

  const missingArguments =
    nextArguments.startsWith(toolCall.arguments) ?
      nextArguments.slice(toolCall.arguments.length)
    : nextArguments

  toolCall.arguments = nextArguments

  if (!missingArguments) {
    return
  }

  yield makeChunk(streamState, {
    delta: getToolCallDelta(toolCall, missingArguments),
    finishReason: null,
  })
}

function* handleCreatedEvent(
  streamState: ResponsesStreamState,
  data: ResponsesStreamEventData,
): Generator<ChatCompletionChunk> {
  syncResponseMetadata(streamState, data)
  yield makeChunk(streamState, {
    delta: { role: "assistant", content: "" },
    finishReason: null,
  })
}

function* handleOutputTextDeltaEvent(
  streamState: ResponsesStreamState,
  data: ResponsesStreamEventData,
): Generator<ChatCompletionChunk> {
  if (!data.delta) {
    return
  }

  yield makeChunk(streamState, {
    delta: { content: data.delta },
    finishReason: null,
  })
}

function* handleOutputItemAddedEvent(
  streamState: ResponsesStreamState,
  data: ResponsesStreamEventData,
): Generator<ChatCompletionChunk> {
  if (data.item?.type !== "function_call") {
    return
  }

  const toolCall = getOrCreateToolCall(streamState, {
    callId: data.item.call_id,
    initialArguments: data.item.arguments ?? "",
    name: data.item.name,
    outputIndex: data.output_index,
  })

  if (!toolCall?.isNew) {
    return
  }

  yield makeChunk(streamState, {
    delta: getNewToolCallDelta(toolCall.toolCall, data.item.arguments ?? ""),
    finishReason: null,
  })
}

function* handleFunctionCallArgumentsDeltaEvent(
  streamState: ResponsesStreamState,
  data: ResponsesStreamEventData,
): Generator<ChatCompletionChunk> {
  if (!data.delta) {
    return
  }

  const existingToolCall = getExistingToolCall(streamState, data)
  if (existingToolCall) {
    existingToolCall.arguments += data.delta
    yield makeChunk(streamState, {
      delta: getToolCallDelta(existingToolCall, data.delta),
      finishReason: null,
    })
    return
  }

  const toolCall = getOrCreateToolCall(streamState, {
    callId: data.call_id,
    initialArguments: data.delta,
    name: data.name,
    outputIndex: data.output_index,
  })

  if (!toolCall) {
    return
  }

  yield makeChunk(streamState, {
    delta: getNewToolCallDelta(toolCall.toolCall, data.delta),
    finishReason: null,
  })
}

function* handleFunctionCallArgumentsDoneEvent(
  streamState: ResponsesStreamState,
  data: ResponsesStreamEventData,
): Generator<ChatCompletionChunk> {
  const existingToolCall = getExistingToolCall(streamState, data)
  if (!existingToolCall) {
    return
  }

  yield* syncToolArguments(streamState, existingToolCall, data.arguments)
}

function getExistingOrCreateCompletedToolCall(
  streamState: ResponsesStreamState,
  data: ResponsesStreamEventData,
): { isNew: boolean; toolCall: ResponsesStreamToolCall } | undefined {
  const existingToolCall = getExistingToolCall(streamState, {
    call_id: data.item?.call_id,
    output_index: data.output_index,
  })

  if (existingToolCall) {
    return { isNew: false, toolCall: existingToolCall }
  }

  return getOrCreateToolCall(streamState, {
    callId: data.item?.call_id,
    initialArguments: data.item?.arguments ?? "",
    name: data.item?.name,
    outputIndex: data.output_index,
  })
}

function* handleOutputItemDoneEvent(
  streamState: ResponsesStreamState,
  data: ResponsesStreamEventData,
): Generator<ChatCompletionChunk> {
  if (data.item?.type !== "function_call") {
    return
  }

  const toolCall = getExistingOrCreateCompletedToolCall(streamState, data)
  if (!toolCall) {
    return
  }

  if (toolCall.isNew) {
    yield makeChunk(streamState, {
      delta: getNewToolCallDelta(toolCall.toolCall, data.item.arguments ?? ""),
      finishReason: null,
    })
  }

  yield* syncToolArguments(streamState, toolCall.toolCall, data.item.arguments)
}

function* handleCompletedEvent(
  streamState: ResponsesStreamState,
  data: ResponsesStreamEventData,
): Generator<ChatCompletionChunk> {
  syncResponseMetadata(streamState, data)
  const hasToolCalls = Object.keys(streamState.toolCallsByCallId).length > 0

  yield makeChunk(streamState, {
    delta: {},
    finishReason: hasToolCalls ? "tool_calls" : "stop",
    usage: translateResponsesUsage(data.response?.usage),
  })
}

export function* translateResponsesStreamEvent(
  event: {
    event: string
    data: ResponsesStreamEventData
  },
  streamState: ResponsesStreamState,
): Generator<ChatCompletionChunk> {
  const { event: eventType, data } = event

  switch (eventType) {
    case "response.created": {
      yield* handleCreatedEvent(streamState, data)
      break
    }

    case "response.in_progress": {
      syncResponseMetadata(streamState, data)
      break
    }

    case "response.output_text.delta": {
      yield* handleOutputTextDeltaEvent(streamState, data)
      break
    }

    case "response.output_item.added": {
      yield* handleOutputItemAddedEvent(streamState, data)
      break
    }

    case "response.function_call_arguments.delta": {
      yield* handleFunctionCallArgumentsDeltaEvent(streamState, data)
      break
    }

    case "response.function_call_arguments.done": {
      yield* handleFunctionCallArgumentsDoneEvent(streamState, data)
      break
    }

    case "response.output_item.done": {
      yield* handleOutputItemDoneEvent(streamState, data)
      break
    }

    case "response.completed": {
      yield* handleCompletedEvent(streamState, data)
      break
    }

    default: {
      break
    }
  }
}

// ── Service function: call the upstream /responses endpoint ──

export async function createResponses(
  payload: ChatCompletionsPayload,
  effort?: string,
) {
  if (!state.copilotToken) throw new Error("Copilot token not found")

  const responsesPayload = translateRequestToResponses(payload, effort)

  const url = `${copilotBaseUrl(state)}/responses`
  consola.debug(`Sending /responses request for model: ${payload.model}`)

  const response = await fetch(url, {
    method: "POST",
    headers: copilotHeaders(state),
    body: JSON.stringify(responsesPayload),
  })

  if (!response.ok) {
    consola.error("Failed to create responses", response)
    throw new HTTPError("Failed to create responses", response)
  }

  if (payload.stream) {
    return events(response)
  }

  const rawResponse = (await response.json()) as ResponsesResponse
  return translateResponsesNonStreaming(rawResponse)
}

import { beforeEach, describe, expect, it } from "bun:test"

import type { AnthropicMessagesPayload } from "~/routes/messages/anthropic-types"

import { state } from "~/lib/state"

import { buildNativeBody } from "./forward-native-messages"

function basePayload(
  overrides: Partial<AnthropicMessagesPayload> = {},
): AnthropicMessagesPayload {
  return {
    model: "claude-sonnet-4-6",
    messages: [{ role: "user", content: "Hello" }],
    max_tokens: 8192,
    ...overrides,
  }
}

function setCatalog(
  ids: Array<string>,
  capabilities?: Record<string, { reasoning_effort?: Array<string> }>,
) {
  state.models = {
    object: "list",
    data: ids.map((id) => ({
      id,
      object: "model",
      created: 0,
      owned_by: "anthropic",
      ...(capabilities?.[id] ?
        {
          capabilities: {
            supports: {
              reasoning_effort: capabilities[id].reasoning_effort,
            },
          },
        }
      : {}),
    })),
  } as unknown as typeof state.models
}

describe("buildNativeBody", () => {
  beforeEach(() => {
    state.is1MContext = false
    setCatalog(["claude-sonnet-4.6", "claude-opus-4.7"], {
      "claude-sonnet-4.6": {
        reasoning_effort: ["low", "medium", "high", "max"],
      },
      "claude-opus-4.7": {
        reasoning_effort: ["low", "medium", "high", "xhigh", "max"],
      },
    })
  })

  describe("stop_sequences sanitization", () => {
    it("strips whitespace-only stop sequences", () => {
      const body = buildNativeBody(basePayload({ stop_sequences: ["\n"] }), {})
      expect(body.stop_sequences).toBeUndefined()
    })

    it("keeps valid stop sequences", () => {
      const body = buildNativeBody(
        basePayload({ stop_sequences: ["END", "STOP"] }),
        {},
      )
      expect(body.stop_sequences).toEqual(["END", "STOP"])
    })

    it("filters mixed stop sequences", () => {
      const body = buildNativeBody(
        basePayload({ stop_sequences: ["\n", "END", " \t ", "STOP"] }),
        {},
      )
      expect(body.stop_sequences).toEqual(["END", "STOP"])
    })

    it("removes field when all entries are whitespace", () => {
      const body = buildNativeBody(
        basePayload({ stop_sequences: ["\n", " ", "\t"] }),
        {},
      )
      expect(body).not.toHaveProperty("stop_sequences")
    })
  })

  describe("thinking normalization", () => {
    it("downgrades adaptive to enabled", () => {
      const body = buildNativeBody(
        basePayload({ thinking: { type: "adaptive" } }),
        {},
      )
      expect(body.thinking).toEqual({
        type: "enabled",
        budget_tokens: Math.max(1024, 8192 - 1),
      })
    })

    it("preserves enabled thinking with budget", () => {
      const body = buildNativeBody(
        basePayload({
          thinking: { type: "enabled", budget_tokens: 4096 },
        }),
        {},
      )
      expect(body.thinking).toEqual({
        type: "enabled",
        budget_tokens: 4096,
      })
    })

    it("enforces minimum budget of 1024", () => {
      const body = buildNativeBody(
        basePayload({
          max_tokens: 1500,
          thinking: { type: "adaptive" },
        }),
        {},
      )
      const thinking = body.thinking as { budget_tokens: number }
      expect(thinking.budget_tokens).toBeGreaterThanOrEqual(1024)
    })

    it("passes disabled thinking through", () => {
      const body = buildNativeBody(
        basePayload({ thinking: { type: "disabled" } }),
        {},
      )
      expect(body.thinking).toEqual({ type: "disabled" })
    })

    it("omits thinking when not specified", () => {
      const body = buildNativeBody(basePayload(), {})
      expect(body.thinking).toBeUndefined()
    })
  })

  describe("effort mapping", () => {
    it("forwards effort via output_config for models with reasoning_effort capability", () => {
      const body = buildNativeBody(
        basePayload({ output_config: { effort: "max" } }),
        {},
      )
      expect(body.output_config).toEqual({ effort: "max" })
    })

    it("forwards effort=xhigh for models that support it", () => {
      const body = buildNativeBody(
        basePayload({
          model: "claude-opus-4-7",
          output_config: { effort: "xhigh" },
        }),
        {},
      )
      expect(body.output_config).toEqual({ effort: "xhigh" })
    })

    it("forwards effort=high via output_config", () => {
      const body = buildNativeBody(
        basePayload({ output_config: { effort: "high" } }),
        {},
      )
      expect(body.output_config).toEqual({ effort: "high" })
    })

    it("maps low effort to disabled thinking when effort is not handled by output_config", () => {
      // Model without reasoning_effort capability
      setCatalog(["claude-sonnet-4.6", "claude-opus-4.7"])
      const body = buildNativeBody(
        basePayload({ output_config: { effort: "low" } }),
        {},
      )
      expect(body.thinking).toEqual({ type: "disabled" })
    })

    it("maps effort to thinking budget for models without reasoning_effort capability", () => {
      // Model without reasoning_effort capability (older model)
      setCatalog(["claude-sonnet-4.6", "claude-opus-4.7"])
      const body = buildNativeBody(
        basePayload({ output_config: { effort: "medium" } }),
        {},
      )
      const thinking = body.thinking as { type: string; budget_tokens: number }
      expect(thinking.type).toBe("enabled")
      expect(thinking.budget_tokens).toBe(Math.floor(8192 * 0.5))
    })

    it("does not override explicit thinking when effort is handled via output_config", () => {
      const body = buildNativeBody(
        basePayload({
          thinking: { type: "enabled", budget_tokens: 2048 },
          output_config: { effort: "max" },
        }),
        {},
      )
      // Effort is handled by output_config, thinking is normalized independently
      expect(body.output_config).toEqual({ effort: "max" })
      const thinking = body.thinking as { type: string; budget_tokens: number }
      expect(thinking.type).toBe("enabled")
      expect(thinking.budget_tokens).toBe(2048)
    })
  })

  describe("field allowlist", () => {
    it("forwards output_config.effort for models with reasoning_effort capability", () => {
      const body = buildNativeBody(
        basePayload({ output_config: { effort: "high" } }),
        {},
      )
      expect(body.output_config).toEqual({ effort: "high" })
    })

    it("does not forward output_config for models without reasoning_effort capability", () => {
      setCatalog(["claude-sonnet-4.6", "claude-opus-4.7"])
      const body = buildNativeBody(
        basePayload({ output_config: { effort: "high" } }),
        {},
      )
      expect(body).not.toHaveProperty("output_config")
    })

    it("does not forward unknown fields", () => {
      const payload = {
        ...basePayload(),
        anthropic_internal: { foo: "bar" },
      } as AnthropicMessagesPayload
      const body = buildNativeBody(payload, {})
      expect(body).not.toHaveProperty("anthropic_internal")
    })

    it("forwards allowed optional fields", () => {
      const body = buildNativeBody(
        basePayload({
          system: "You are helpful",
          temperature: 0.7,
          top_p: 0.9,
          top_k: 40,
        }),
        {},
      )
      expect(body.system).toBe("You are helpful")
      expect(body.temperature).toBe(0.7)
      expect(body.top_p).toBe(0.9)
      expect(body.top_k).toBe(40)
    })
  })

  describe("overrides", () => {
    it("applies overrides last", () => {
      const body = buildNativeBody(basePayload(), { stream: true })
      expect(body.stream).toBe(true)
    })
  })

  describe("1M model selection", () => {
    it("keeps the base model when 1M context is not requested", () => {
      const body = buildNativeBody(
        basePayload({ model: "claude-opus-4.7" }),
        {},
        false,
      )
      expect(body.model).toBe("claude-opus-4.7")
    })

    it("falls back to base model when no -1m variant exists (1M is now default)", () => {
      const body = buildNativeBody(
        basePayload({ model: "claude-opus-4.7" }),
        {},
        true,
      )
      expect(body.model).toBe("claude-opus-4.7")
    })

    it("strips [1m] suffix and resolves to base model (1M is now default)", () => {
      const body = buildNativeBody(
        basePayload({ model: "claude-opus-4.7[1m]" }),
        {},
        false,
      )
      expect(body.model).toBe("claude-opus-4.7")
    })
  })
})

import consola from "consola"
import { events } from "fetch-event-stream"

import type { AnthropicMessagesPayload } from "~/routes/messages/anthropic-types"

import { copilotBaseUrl, copilotHeaders } from "~/lib/api-config"
import { HTTPError } from "~/lib/error"
import { anthropicToCopilotModelId } from "~/lib/model-mapping"
import { state } from "~/lib/state"

/**
 * Detect Claude model generation from the copilot model ID.
 *
 * Thinking type support varies by generation:
 *   Older (haiku-4.5, sonnet-4/4.5, opus-4.5): disabled, enabled
 *   4.6   (sonnet-4.6, opus-4.6[-1m]):          disabled, enabled, adaptive
 *   4.7+  (opus-4.7[-1m-internal]):              disabled, adaptive (rejects enabled)
 *
 * Future models default to adaptive (the trend is clear).
 */
type ModelGeneration = "older" | "4.6" | "4.7+"

/** Models that only accept enabled (not adaptive) */
const OLDER_MODELS = ["haiku-4.5", "sonnet-4.5", "sonnet-4", "opus-4.5"]

function detectGeneration(copilotModelId: string): ModelGeneration {
  // Check older models first (allowlist approach)
  if (OLDER_MODELS.some((m) => copilotModelId.includes(m))) return "older"
  if (copilotModelId.includes("4.6")) return "4.6"
  // 4.7 and all future models default to adaptive
  return "4.7+"
}

/**
 * Compute a thinking budget from effort level and max_tokens.
 */
function budgetFromEffort(
  effort: string | undefined,
  maxTokens: number,
  existingBudget: number | undefined,
): number {
  let budget: number
  switch (effort) {
    case "low": {
      return 0
    } // caller handles this as disabled
    case "medium": {
      budget = existingBudget ?? Math.max(1024, Math.floor(maxTokens * 0.5))
      break
    }
    case "high": {
      budget = existingBudget ?? Math.max(1024, Math.floor(maxTokens * 0.8))
      break
    }
    case "max": {
      budget = Math.max(1024, maxTokens - 1)
      break
    }
    default: {
      budget = existingBudget ?? Math.max(1024, maxTokens - 1)
    }
  }
  // budget_tokens must be strictly less than max_tokens
  return Math.min(budget, maxTokens - 1)
}

interface NormalizeThinkingOpts {
  thinking: AnthropicMessagesPayload["thinking"]
  maxTokens: number
  generation: ModelGeneration
  effort?: "low" | "medium" | "high" | "max"
}

/**
 * Normalize thinking config for the upstream Copilot /v1/messages endpoint.
 *
 * Applies per-generation rules:
 *   - Older models: downgrade adaptive → enabled (they reject adaptive)
 *   - 4.6 models: pass through as-is (they accept everything)
 *   - 4.7 models: upgrade enabled → adaptive (they reject enabled)
 *
 * Also maps output_config.effort to budget_tokens.
 */
function normalizeThinking(
  opts: NormalizeThinkingOpts,
): Record<string, unknown> | undefined {
  const { thinking, maxTokens, generation, effort } = opts
  // Low effort: disable thinking entirely regardless of generation
  if (effort === "low") {
    return { type: "disabled" }
  }

  // If no thinking config and no effort signal, nothing to do
  if (!thinking && !effort) return undefined

  const requestedType = thinking?.type ?? "enabled"

  // Disabled is universally supported
  if (requestedType === "disabled") return thinking

  const budgetTokens = budgetFromEffort(
    effort,
    maxTokens,
    thinking?.budget_tokens,
  )

  switch (generation) {
    case "4.6": {
      // 4.6 accepts everything — pass through type as-is
      // adaptive does NOT accept budget_tokens, only enabled does
      if (requestedType === "adaptive") {
        return { type: "adaptive" }
      }
      return { type: "enabled", budget_tokens: budgetTokens }
    }

    case "4.7+": {
      // 4.7+ rejects 'enabled' — must use adaptive (no budget_tokens)
      return { type: "adaptive" }
    }

    default: {
      // Older models reject 'adaptive' — must use enabled
      return { type: "enabled", budget_tokens: budgetTokens }
    }
  }
}

/** Whitelist of optional fields safe to forward to Copilot /v1/messages */
const OPTIONAL_FIELDS = [
  "system",
  "metadata",
  "stop_sequences",
  "temperature",
  "top_p",
  "top_k",
  "tools",
  "tool_choice",
  "service_tier",
] as const

/**
 * Check whether a model supports output_config.effort by looking at
 * the advertised reasoning_effort capabilities from the model catalog.
 */
function supportsEffort(copilotModelId: string): boolean {
  const model = state.models?.data.find((m) => m.id === copilotModelId)
  const supports = (model?.capabilities as Record<string, unknown> | undefined)
    ?.supports as Record<string, unknown> | undefined
  const efforts = supports?.reasoning_effort
  return Array.isArray(efforts) && efforts.length > 0
}

interface ResolveEffortOpts {
  copilotModelId: string
  effort: string | undefined
  body: Record<string, unknown>
  outputConfig: Record<string, unknown> | undefined
}

/**
 * Resolve effort by forwarding output_config.effort directly.
 * The upstream API validates supported values per model.
 * Returns whether effort was handled.
 */
function resolveEffort(opts: ResolveEffortOpts): boolean {
  const { copilotModelId, effort, body, outputConfig } = opts
  if (!effort) return false

  if (supportsEffort(copilotModelId)) {
    body.output_config = { ...outputConfig, effort }
    return true
  }

  return false
}

/**
 * Build a sanitized request body for the upstream Copilot /v1/messages endpoint.
 * Only forward fields that the Copilot API accepts — strip extras like
 * output_config that Claude Code sends but Copilot doesn't support.
 */
export function buildNativeBody(
  payload: AnthropicMessagesPayload,
  overrides: Record<string, unknown>,
  is1M?: boolean,
): Record<string, unknown> {
  const copilotModelId = anthropicToCopilotModelId(
    payload.model,
    is1M ?? state.is1MContext,
  )

  const body: Record<string, unknown> = {
    model: copilotModelId,
    messages: payload.messages,
    max_tokens: payload.max_tokens,
  }

  for (const field of OPTIONAL_FIELDS) {
    if (payload[field] !== undefined) {
      body[field] = payload[field]
    }
  }

  // Sanitize stop_sequences: Copilot rejects whitespace-only entries (e.g. "\n" from Buddy)
  if (body.stop_sequences) {
    const filtered = (body.stop_sequences as Array<string>).filter((s) =>
      s.trim(),
    )
    if (filtered.length > 0) {
      body.stop_sequences = filtered
    } else {
      delete body.stop_sequences
    }
  }

  const effort = payload.output_config?.effort
  const generation = detectGeneration(copilotModelId)

  const effortHandled = resolveEffort({
    copilotModelId,
    effort,
    body,
    outputConfig: payload.output_config,
  })

  const thinking = normalizeThinking({
    thinking: payload.thinking,
    maxTokens: payload.max_tokens,
    generation,
    effort: effortHandled ? undefined : effort,
  })
  if (thinking) body.thinking = thinking

  Object.assign(body, overrides)

  return body
}

/**
 * Forward a /v1/messages request directly to the upstream Copilot API's
 * native Anthropic /v1/messages endpoint, with only supported fields.
 */
export async function forwardNativeMessages(
  payload: AnthropicMessagesPayload,
  streamOverride?: boolean,
  is1M?: boolean,
): Promise<Response> {
  const overrides: Record<string, unknown> = {}
  if (streamOverride !== undefined) overrides.stream = streamOverride

  const body = buildNativeBody(payload, overrides, is1M)

  const url = `${copilotBaseUrl(state)}/v1/messages`

  consola.debug(
    `Native passthrough: ${payload.model} -> ${body.model as string} via ${url}`,
  )

  const response = await fetch(url, {
    method: "POST",
    headers: copilotHeaders(state),
    body: JSON.stringify(body),
  })

  if (!response.ok) {
    throw new HTTPError(
      `Native /v1/messages request failed for model ${body.model as string}`,
      response,
    )
  }

  return response
}

/**
 * Forward a native /v1/messages request and return the parsed JSON response.
 */
export async function forwardNativeMessagesNonStreaming(
  payload: AnthropicMessagesPayload,
  is1M?: boolean,
) {
  const response = await forwardNativeMessages(payload, false, is1M)
  return await response.json()
}

/**
 * Forward a native /v1/messages request in streaming mode and yield SSE events.
 */
export async function* forwardNativeMessagesStreaming(
  payload: AnthropicMessagesPayload,
  is1M?: boolean,
) {
  const response = await forwardNativeMessages(payload, true, is1M)

  const stream = events(response)
  for await (const event of stream) {
    if (!event.data || event.data === "[DONE]") continue
    try {
      const data = JSON.parse(event.data) as Record<string, unknown>
      yield { type: (event.event ?? data.type) as string, data }
    } catch {
      consola.warn("Failed to parse native stream event:", event.data)
    }
  }
}
